  1→import type Database from 'better-sqlite3';
  2→import { SCHEMA_SQL, CURRENT_SCHEMA_VERSION } from './schema.js';
  3→
  4→export interface MigrationResult {
  5→  v6Applied: boolean;
  6→  v7Applied: boolean;
  7→}
  8→
  9→/**
 10→ * Apply schema migrations to the database.
 11→ * Called once on startup before any reads or writes.
 12→ *
 13→ * Version 1: Initial schema (projects, sessions, messages, insights, usage_stats)
 14→ * Version 2: Add compound index on insights(confidence DESC, timestamp DESC) for depth-ordered export queries
 15→ * Version 3: Add session_facets table for cross-session analysis
 16→ * Version 4: Add reflect_snapshots table for caching LLM-generated synthesis results
 17→ * Version 5: Add deleted_at column to sessions for soft-delete (user-initiated hide)
 18→ * Version 6: Add compact_count, auto_compact_count, slash_commands columns to sessions
 19→ * Version 7: Add analysis_usage table for tracking LLM analysis costs per session
 20→ */
 21→export function runMigrations(db: Database.Database): MigrationResult {
 22→  // Create schema_version table first if it doesn't exist.
 23→  // This table is created inline (not via SCHEMA_SQL) so migrations can check it.
 24→  db.exec(`
 25→    CREATE TABLE IF NOT EXISTS schema_version (
 26→      version    INTEGER PRIMARY KEY,
 27→      applied_at TEXT NOT NULL DEFAULT (datetime('now'))
 28→    );
 29→  `);
 30→
 31→  const currentVersion = getCurrentVersion(db);
 32→
 33→  if (currentVersion < 1) {
 34→    applyV1(db);
 35→  }
 36→
 37→  if (currentVersion < 2) {
 38→    applyV2(db);
 39→  }
 40→
 41→  if (currentVersion < 3) {
 42→    applyV3(db);
 43→  }
 44→
 45→  if (currentVersion < 4) {
 46→    applyV4(db);
 47→  }
 48→
 49→  if (currentVersion < 5) {
 50→    applyV5(db);
 51→  }
 52→
 53→  let v6Applied = false;
 54→  if (currentVersion < 6) {
 55→    applyV6(db);
 56→    v6Applied = true;
 57→  }
 58→
 59→  let v7Applied = false;
 60→  if (currentVersion < 7) {
 61→    applyV7(db);
 62→    v7Applied = true;
 63→  }
 64→
 65→  return { v6Applied, v7Applied };
 66→}
 67→
 68→function getCurrentVersion(db: Database.Database): number {
 69→  const row = db.prepare('SELECT MAX(version) as v FROM schema_version').get() as { v: number | null };
 70→  return row.v ?? 0;
 71→}
 72→
 73→function applyV1(db: Database.Database): void {
 74→  db.exec(SCHEMA_SQL);
 75→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(1);
 76→}
 77→
 78→function applyV2(db: Database.Database): void {
 79→  db.exec(`CREATE INDEX IF NOT EXISTS idx_insights_confidence_timestamp ON insights(confidence DESC, timestamp DESC)`);
 80→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(2);
 81→}
 82→
 83→function applyV3(db: Database.Database): void {
 84→  db.exec(`
 85→    CREATE TABLE IF NOT EXISTS session_facets (
 86→      session_id              TEXT PRIMARY KEY REFERENCES sessions(id),
 87→      outcome_satisfaction    TEXT NOT NULL,
 88→      workflow_pattern        TEXT,
 89→      had_course_correction   INTEGER NOT NULL DEFAULT 0,
 90→      course_correction_reason TEXT,
 91→      iteration_count         INTEGER NOT NULL DEFAULT 0,
 92→      friction_points         TEXT,
 93→      effective_patterns      TEXT,
 94→      extracted_at            TEXT NOT NULL DEFAULT (datetime('now')),
 95→      analysis_version        TEXT NOT NULL DEFAULT '1.0.0'
 96→    );
 97→
 98→    CREATE INDEX IF NOT EXISTS idx_facets_outcome ON session_facets(outcome_satisfaction);
 99→    CREATE INDEX IF NOT EXISTS idx_facets_workflow ON session_facets(workflow_pattern);
100→  `);
101→
102→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(3);
103→}
104→
105→function applyV4(db: Database.Database): void {
106→  db.exec(`
107→    CREATE TABLE IF NOT EXISTS reflect_snapshots (
108→      period        TEXT NOT NULL,
109→      project_id    TEXT NOT NULL DEFAULT '__all__',
110→      results_json  TEXT NOT NULL,
111→      generated_at  TEXT NOT NULL,
112→      window_start  TEXT,
113→      window_end    TEXT NOT NULL,
114→      session_count INTEGER NOT NULL,
115→      facet_count   INTEGER NOT NULL,
116→      PRIMARY KEY (period, project_id)
117→    );
118→  `);
119→
120→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(4);
121→}
122→
123→function applyV5(db: Database.Database): void {
124→  db.exec(`ALTER TABLE sessions ADD COLUMN deleted_at TEXT`);
125→  db.exec(`CREATE INDEX IF NOT EXISTS idx_sessions_deleted_at ON sessions(deleted_at)`);
126→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(5);
127→}
128→
129→function applyV6(db: Database.Database): void {
130→  db.exec(`ALTER TABLE sessions ADD COLUMN compact_count INTEGER NOT NULL DEFAULT 0`);
131→  db.exec(`ALTER TABLE sessions ADD COLUMN auto_compact_count INTEGER NOT NULL DEFAULT 0`);
132→  db.exec(`ALTER TABLE sessions ADD COLUMN slash_commands TEXT NOT NULL DEFAULT '[]'`);
133→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(6);
134→}
135→
136→function applyV7(db: Database.Database): void {
137→  db.exec(`
138→    CREATE TABLE IF NOT EXISTS analysis_usage (
139→      session_id            TEXT NOT NULL REFERENCES sessions(id),
140→      analysis_type         TEXT NOT NULL,
141→      provider              TEXT NOT NULL,
142→      model                 TEXT NOT NULL,
143→      input_tokens          INTEGER NOT NULL DEFAULT 0,
144→      output_tokens         INTEGER NOT NULL DEFAULT 0,
145→      cache_creation_tokens INTEGER NOT NULL DEFAULT 0,
146→      cache_read_tokens     INTEGER NOT NULL DEFAULT 0,
147→      estimated_cost_usd    REAL NOT NULL DEFAULT 0,
148→      duration_ms           INTEGER,
149→      chunk_count           INTEGER NOT NULL DEFAULT 1,
150→      analyzed_at           TEXT NOT NULL DEFAULT (datetime('now')),
151→      PRIMARY KEY (session_id, analysis_type)
152→    )
153→  `);
154→  db.exec(`
155→    CREATE INDEX IF NOT EXISTS idx_analysis_usage_analyzed_at
156→      ON analysis_usage(analyzed_at DESC)
157→  `);
158→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(7);
159→}
