  1→import { serve } from '@hono/node-server';
  2→import { serveStatic } from '@hono/node-server/serve-static';
  3→import { Hono } from 'hono';
  4→import { existsSync, readFileSync } from 'fs';
  5→import { relative, join } from 'path';
  6→import { openUrl } from '@code-insights/cli/utils/browser';
  7→import { shutdownTelemetry } from '@code-insights/cli/utils/telemetry';
  8→import projectsRouter from './routes/projects.js';
  9→import sessionsRouter from './routes/sessions.js';
 10→import messagesRouter from './routes/messages.js';
 11→import insightsRouter from './routes/insights.js';
 12→import analysisRouter from './routes/analysis.js';
 13→import analyticsRouter from './routes/analytics.js';
 14→import configRouter from './routes/config.js';
 15→import exportRouter from './routes/export.js';
 16→import telemetryRouter from './routes/telemetry.js';
 17→import facetsRouter from './routes/facets.js';
 18→import reflectRouter from './routes/reflect.js';
 19→
 20→export interface ServerOptions {
 21→  port: number;
 22→  // Absolute path to the dashboard/dist directory
 23→  staticDir: string;
 24→  openBrowser: boolean;
 25→}
 26→
 27→/**
 28→ * Create the Hono app with all API routes mounted.
 29→ * Does NOT add static file serving or call serve() — that's startServer's job.
 30→ * Exported so tests can use app.request() without starting a real server.
 31→ */
 32→export function createApp(): Hono {
 33→  const app = new Hono();
 34→
 35→  // Global error handler — prevents stack trace leakage to clients.
 36→  // Detects malformed JSON bodies (SyntaxError) and returns 400 instead of 500.
 37→  app.onError((err, c) => {
 38→    if (err instanceof SyntaxError && err.message.includes('JSON')) {
 39→      return c.json({ error: 'Invalid JSON in request body' }, 400);
 40→    }
 41→    console.error(err);
 42→    return c.json({ error: 'Internal server error' }, 500);
 43→  });
 44→
 45→  // API routes — all under /api
 46→  app.route('/api/projects', projectsRouter);
 47→  app.route('/api/sessions', sessionsRouter);
 48→  app.route('/api/messages', messagesRouter);
 49→  app.route('/api/insights', insightsRouter);
 50→  app.route('/api/analysis', analysisRouter);
 51→  app.route('/api/analytics', analyticsRouter);
 52→  app.route('/api/config', configRouter);
 53→  app.route('/api/export', exportRouter);
 54→  app.route('/api/telemetry', telemetryRouter);
 55→  app.route('/api/facets', facetsRouter);
 56→  app.route('/api/reflect', reflectRouter);
 57→
 58→  // Health check
 59→  app.get('/api/health', (c) => c.json({ ok: true, version: '0.1.0' }));
 60→
 61→  // API 404 catch-all — must come AFTER all /api sub-routers and BEFORE static serving.
 62→  // Without this, unmatched /api/* routes fall through to the SPA fallback and return
 63→  // index.html as 200, which breaks API clients expecting JSON errors.
 64→  app.all('/api/*', (c) => c.json({ error: 'Not found' }, 404));
 65→
 66→  return app;
 67→}
 68→
 69→/**
 70→ * Start the Code Insights local dashboard server.
 71→ * Calls createApp(), adds static file serving + SPA fallback if staticDir exists,
 72→ * then calls serve().
 73→ * Called by the CLI `dashboard` command.
 74→ */
 75→export async function startServer(options: ServerOptions): Promise<void> {
 76→  const { port, staticDir, openBrowser } = options;
 77→
 78→  const app = createApp();
 79→
 80→  // Static file serving — only if the dashboard has been built.
 81→  // serveStatic requires a path relative to process.cwd(), not an absolute path.
 82→  if (existsSync(staticDir)) {
 83→    const relativeStaticDir = relative(process.cwd(), staticDir);
 84→    app.use('/*', serveStatic({ root: relativeStaticDir }));
 85→
 86→    // Cache index.html at startup — avoids a readFileSync on every SPA navigation
 87→    // request, which would be a pointless disk read for a file that never changes
 88→    // while the server is running.
 89→    const indexPath = join(staticDir, 'index.html');
 90→    const indexHtml = existsSync(indexPath) ? readFileSync(indexPath, 'utf-8') : null;
 91→
 92→    // SPA fallback: any non-API route not matched by serveStatic serves index.html
 93→    // so react-router can handle client-side routing.
 94→    app.get('*', (c) => {
 95→      if (indexHtml) return c.html(indexHtml);
 96→      return c.text('Dashboard not found. Run pnpm build first.', 404);
 97→    });
 98→  } else {
 99→    // Dashboard not built — serve a helpful message
100→    app.get('*', (c) =>
101→      c.html(`
102→        <html><body style="font-family:monospace;padding:2rem">
103→          <h2>Code Insights Dashboard</h2>
104→          <p>The dashboard has not been built yet.</p>
105→          <pre>pnpm install &amp;&amp; pnpm build</pre>
106→          <p>Then restart the server.</p>
107→        </body></html>
108→      `),
109→    );
110→  }
111→
112→  // Graceful shutdown: flush PostHog events before exit, then let the process
113→  // 'exit' handler in cli/src/db/client.ts run WAL checkpoint via closeDb().
114→  // 3s timeout guards against PostHog SDK stalling on network issues.
115→  const shutdown = async () => {
116→    await Promise.race([
117→      shutdownTelemetry(),
118→      new Promise<void>((resolve) => setTimeout(resolve, 3000)),
119→    ]);
120→    process.exit(0);
121→  };
122→  process.on('SIGINT', () => { void shutdown(); });
123→  process.on('SIGTERM', () => { void shutdown(); });
124→
125→  serve({ fetch: app.fetch, port }, (info) => {
126→    const url = `http://localhost:${info.port}`;
127→    console.log(`  Code Insights dashboard running at ${url}`);
128→    if (openBrowser) {
129→      openUrl(url);
130→    }
131→  });
132→}
133→

 1→import { Hono } from 'hono';
 2→import { getDb } from '@code-insights/cli/db/client';
 3→import { parseIntParam } from '../utils.js';
 4→
 5→const app = new Hono();
 6→
 7→app.get('/', (c) => {
 8→  const db = getDb();
 9→  const { limit, offset } = c.req.query();
10→  const projects = db.prepare(`
11→    SELECT id, name, path, git_remote_url, session_count, last_activity,
12→           total_input_tokens, total_output_tokens, cache_creation_tokens,
13→           cache_read_tokens, estimated_cost_usd, created_at, updated_at
14→    FROM projects
15→    ORDER BY last_activity DESC
16→    LIMIT ? OFFSET ?
17→  `).all(parseIntParam(limit, 100), parseIntParam(offset, 0));
18→  return c.json({ projects });
19→});
20→
21→app.get('/:id', (c) => {
22→  const db = getDb();
23→  const project = db.prepare(`
24→    SELECT id, name, path, git_remote_url, session_count, last_activity,
25→           total_input_tokens, total_output_tokens, cache_creation_tokens,
26→           cache_read_tokens, estimated_cost_usd, created_at, updated_at
27→    FROM projects
28→    WHERE id = ?
29→  `).get(c.req.param('id'));
30→  if (!project) return c.json({ error: 'Not found' }, 404);
31→  return c.json({ project });
32→});
33→
34→export default app;
