  1→import { Hono } from 'hono';
  2→import { getDb } from '@code-insights/cli/db/client';
  3→import { parseIntParam } from '../utils.js';
  4→
  5→const app = new Hono();
  6→
  7→app.get('/', (c) => {
  8→  const db = getDb();
  9→  const { projectId, sourceTool, limit, offset } = c.req.query();
 10→
 11→  const conditions: string[] = [];
 12→  const params: (string | number)[] = [];
 13→
 14→  if (projectId) {
 15→    conditions.push('project_id = ?');
 16→    params.push(projectId);
 17→  }
 18→  if (sourceTool) {
 19→    conditions.push('source_tool = ?');
 20→    params.push(sourceTool);
 21→  }
 22→
 23→  conditions.push('deleted_at IS NULL');
 24→  const where = `WHERE ${conditions.join(' AND ')}`;
 25→  const sessions = db.prepare(`
 26→    SELECT id, project_id, project_name, project_path, git_remote_url,
 27→           summary, custom_title, generated_title, title_source, session_character,
 28→           started_at, ended_at, message_count, user_message_count,
 29→           assistant_message_count, tool_call_count, git_branch,
 30→           claude_version, source_tool, device_id, device_hostname,
 31→           device_platform, synced_at, total_input_tokens, total_output_tokens,
 32→           cache_creation_tokens, cache_read_tokens, estimated_cost_usd,
 33→           models_used, primary_model, usage_source,
 34→           compact_count, auto_compact_count, slash_commands
 35→    FROM sessions
 36→    ${where}
 37→    ORDER BY started_at DESC
 38→    LIMIT ? OFFSET ?
 39→  `).all(...params, parseIntParam(limit, 50), parseIntParam(offset, 0));
 40→
 41→  return c.json({ sessions });
 42→});
 43→
 44→// GET /api/sessions/deleted/count — count of soft-deleted sessions for a project
 45→// IMPORTANT: registered before /:id so "deleted" isn't matched as a session ID
 46→app.get('/deleted/count', (c) => {
 47→  const db = getDb();
 48→  const { projectId } = c.req.query();
 49→  let row: { count: number };
 50→  if (projectId) {
 51→    row = db.prepare(
 52→      `SELECT COUNT(*) AS count FROM sessions WHERE deleted_at IS NOT NULL AND project_id = ?`
 53→    ).get(projectId) as { count: number };
 54→  } else {
 55→    row = db.prepare(
 56→      `SELECT COUNT(*) AS count FROM sessions WHERE deleted_at IS NOT NULL`
 57→    ).get() as { count: number };
 58→  }
 59→  return c.json({ count: row.count });
 60→});
 61→
 62→app.get('/:id', (c) => {
 63→  const db = getDb();
 64→  const session = db.prepare(`
 65→    SELECT id, project_id, project_name, project_path, git_remote_url,
 66→           summary, custom_title, generated_title, title_source, session_character,
 67→           started_at, ended_at, message_count, user_message_count,
 68→           assistant_message_count, tool_call_count, git_branch,
 69→           claude_version, source_tool, device_id, device_hostname,
 70→           device_platform, synced_at, total_input_tokens, total_output_tokens,
 71→           cache_creation_tokens, cache_read_tokens, estimated_cost_usd,
 72→           models_used, primary_model, usage_source,
 73→           compact_count, auto_compact_count, slash_commands
 74→    FROM sessions WHERE id = ? AND deleted_at IS NULL
 75→  `).get(c.req.param('id'));
 76→  if (!session) return c.json({ error: 'Not found' }, 404);
 77→  return c.json({ session });
 78→});
 79→
 80→app.patch('/:id', async (c) => {
 81→  const db = getDb();
 82→  const body = await c.req.json<{ customTitle?: string }>();
 83→  const { customTitle } = body;
 84→  if (customTitle === undefined) {
 85→    return c.json({ error: 'customTitle is required' }, 400);
 86→  }
 87→  const result = db.prepare(
 88→    'UPDATE sessions SET custom_title = ? WHERE id = ? AND deleted_at IS NULL'
 89→  ).run(customTitle || null, c.req.param('id'));
