 1→import { useEffect, useRef } from 'react';
 2→import { BrowserRouter, Routes, Route, Navigate, useLocation, useSearchParams } from 'react-router';
 3→import { capturePageView, captureDashboardLoaded } from '@/lib/telemetry';
 4→import { Layout } from '@/components/layout/Layout';
 5→import DashboardPage from '@/pages/DashboardPage';
 6→import SessionsPage from '@/pages/SessionsPage';
 7→import SessionDetailPage from '@/pages/SessionDetailPage';
