11→import ExportPage from '@/pages/ExportPage';
12→import JournalPage from '@/pages/JournalPage';
13→import PatternsPage from '@/pages/PatternsPage';
14→
15→const ROUTE_TITLES: Record<string, string> = {
16→  '/dashboard': 'Dashboard',
17→  '/sessions': 'Sessions',
18→  '/insights': 'Insights',
19→  '/analytics': 'Analytics',
20→  '/patterns': 'Patterns',
21→  '/export': 'Export',
22→  '/journal': 'Journal',
23→  '/settings': 'Settings',
24→};
25→
26→function RouteEffects() {
27→  const { pathname } = useLocation();
28→  const [searchParams] = useSearchParams();
29→  const insightParam = searchParams.get('insight');
30→  const navStartRef = useRef<number>(Date.now());
31→
32→  // Scroll to top on route change, unless deep-linking to a specific insight
33→  useEffect(() => {
34→    const isInsightDeepLink = pathname === '/insights' && insightParam;
35→    if (!isInsightDeepLink) {
36→      window.scrollTo(0, 0);
37→    }
38→  }, [pathname, insightParam]);
39→
40→  // Update document.title per route, track page views, and capture dashboard_loaded
41→  useEffect(() => {
42→    const segment = '/' + pathname.split('/')[1];
43→    const page = ROUTE_TITLES[segment];
44→    document.title = page ? `${page} — Code Insights` : 'Code Insights';
45→
46→    // Track page view on every route change
47→    capturePageView(pathname);
48→
49→    // Capture dashboard_loaded with time since navigation started
50→    if (page) {
51→      const loadTimeMs = Date.now() - navStartRef.current;
52→      captureDashboardLoaded(page.toLowerCase(), loadTimeMs);
53→    }
54→    // Reset nav start for next navigation
55→    navStartRef.current = Date.now();
56→  }, [pathname]);
57→
58→  return null;
59→}
60→
61→export default function App() {
62→  return (
63→    <BrowserRouter>
64→      <RouteEffects />
65→      <Routes>
66→        <Route element={<Layout />}>
67→          <Route index element={<Navigate to="/dashboard" replace />} />
68→          <Route path="/dashboard" element={<DashboardPage />} />
69→          <Route path="/sessions" element={<SessionsPage />} />
70→          <Route path="/sessions/:id" element={<SessionDetailPage />} />
71→          <Route path="/insights" element={<InsightsPage />} />
72→          <Route path="/analytics" element={<AnalyticsPage />} />
73→          <Route path="/patterns" element={<PatternsPage />} />
74→          <Route path="/settings" element={<SettingsPage />} />
75→          <Route path="/export" element={<ExportPage />} />
76→          <Route path="/journal" element={<JournalPage />} />
77→          <Route path="*" element={<Navigate to="/dashboard" replace />} />
78→        </Route>
79→      </Routes>
80→    </BrowserRouter>
81→  );
82→}
