 19→// GET /api/analysis/usage?sessionId=X
 20→// Returns recorded analysis token usage and cost for a session.
 21→// Returns an empty usage array (not 404) for sessions with no recorded usage —
 22→// this is expected for sessions analyzed before V7 or not yet analyzed.
 23→app.get('/usage', async (c) => {
 24→  const sessionId = c.req.query('sessionId');
 25→  if (!sessionId) {
 26→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
 27→  }
 28→
 29→  const usage = getSessionAnalysisUsage(sessionId);
 30→
 31→  // Compute total cost and cache savings across all analysis types.
 32→  let totalCostUsd = 0;
 33→  let cacheSavingsUsd = 0;
 34→
 35→  for (const row of usage) {
 36→    totalCostUsd += row.estimated_cost_usd;
 37→
 38→    // Cache savings = what the user would have paid without cache minus what they paid.
 39→    // Applies only to Anthropic (cache read = 10% of input price; savings = 90%).
 40→    if (row.provider === 'anthropic' && row.cache_read_tokens > 0) {
 41→      // We need the input price to compute savings — use calculateAnalysisCost on the
 42→      // cached read tokens at full price vs discounted price.
 43→      const fullCacheCost = calculateAnalysisCost(row.provider, row.model, {
 44→        inputTokens: row.cache_read_tokens,
 45→        outputTokens: 0,
 46→      });
 47→      const actualCacheCost = calculateAnalysisCost(row.provider, row.model, {
 48→        inputTokens: 0,
 49→        outputTokens: 0,
 50→        cacheReadTokens: row.cache_read_tokens,
 51→      });
 52→      cacheSavingsUsd += fullCacheCost - actualCacheCost;
 53→    }
 54→  }
 55→
 56→  return c.json({
 57→    usage,
 58→    totalCostUsd: Math.round(totalCostUsd * 1_000_000) / 1_000_000,
 59→    cacheSavingsUsd: Math.round(cacheSavingsUsd * 1_000_000) / 1_000_000,
 60→  });
 61→});
