 63→/** Auto-apply an LLM-generated summary title as the session's generated_title. */
 64→function applyGeneratedTitle(sessionId: string, insights: Array<{ type: string; title?: string }>) {
 65→  const summaryInsight = insights.find(i => i.type === 'summary');
 66→  if (!summaryInsight?.title) return;
 67→  const db = getDb();
