 88→  const messages = loadSessionMessages(db, body.sessionId);
 89→
 90→  const startTime = Date.now();
 91→  const result = await analyzeSession(session, messages);
 92→  trackAnalysisResult('session', result, startTime, {
 93→    onSuccess: () => {
 94→      trackEvent('insight_generated', { type: 'session', count: result.insights.length });
 95→      applyGeneratedTitle(body.sessionId!, result.insights);
 96→    },
 97→  });
 98→  return c.json(result, result.success ? 200 : 422);
