 1→import { Hono } from 'hono';
 2→import { getDb } from '@code-insights/cli/db/client';
 3→
 4→const app = new Hono();
 5→
 6→const VALID_RANGES = ['7d', '30d', '90d', 'all'] as const;
 7→type Range = typeof VALID_RANGES[number];
 8→
 9→// Dashboard overview stats for a given time range (e.g. ?range=7d|30d|90d|all)
10→app.get('/dashboard', (c) => {
11→  const db = getDb();
12→  const { range = '7d' } = c.req.query();
13→
14→  if (!VALID_RANGES.includes(range as Range)) {
15→    return c.json({ error: `Invalid range. Must be one of: ${VALID_RANGES.join(', ')}` }, 400);
16→  }
17→
18→  let periodStart: string | null = null;
19→  const now = new Date();
20→  if (range === '7d') {
21→    periodStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
22→  } else if (range === '30d') {
23→    periodStart = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
24→  } else if (range === '90d') {
25→    periodStart = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000).toISOString();
26→  }
27→
28→  const where = periodStart
29→    ? 'WHERE started_at >= ? AND deleted_at IS NULL'
30→    : 'WHERE deleted_at IS NULL';
31→  const params = periodStart ? [periodStart] : [];
32→
33→  const stats = db.prepare(`
34→    SELECT
35→      COUNT(*) AS session_count,
36→      COUNT(DISTINCT project_id) AS active_projects,
37→      SUM(message_count) AS total_messages,
38→      SUM(tool_call_count) AS total_tool_calls,
39→      CAST(COALESCE(SUM(
40→        CASE WHEN ended_at IS NOT NULL AND started_at IS NOT NULL
41→          THEN (julianday(ended_at) - julianday(started_at)) * 1440
42→          ELSE 0
43→        END
44→      ), 0) AS INTEGER) AS total_duration_min,
45→      SUM(total_input_tokens) AS total_input_tokens,
46→      SUM(total_output_tokens) AS total_output_tokens,
47→      SUM(cache_creation_tokens) AS cache_creation_tokens,
48→      SUM(cache_read_tokens) AS cache_read_tokens,
49→      SUM(estimated_cost_usd) AS estimated_cost_usd
50→    FROM sessions ${where}
51→  `).get(...params);
52→
53→  return c.json({ range, stats });
54→});
55→
56→// Global cumulative usage stats
57→app.get('/usage', (c) => {
58→  const db = getDb();
59→  const stats = db.prepare(`
60→    SELECT total_input_tokens, total_output_tokens, cache_creation_tokens,
61→           cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at
62→    FROM usage_stats WHERE id = 1
63→  `).get();
64→  return c.json({ stats: stats ?? null });
65→});
66→
67→export default app;
68→

