  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { jsonrepair } from 'jsonrepair';
  5→import { createLLMClient } from '../llm/client.js';
  6→import { requireLLM } from './route-helpers.js';
  7→import { extractJsonPayload } from '../llm/response-parsers.js';
  8→import {
  9→  FRICTION_WINS_SYSTEM_PROMPT,
 10→  generateFrictionWinsPrompt,
 11→  RULES_SKILLS_SYSTEM_PROMPT,
 12→  generateRulesSkillsPrompt,
 13→  WORKING_STYLE_SYSTEM_PROMPT,
 14→  generateWorkingStylePrompt,
 15→} from '../llm/reflect-prompts.js';
 16→import { buildWhereClause, buildPeriodFilter, parseIsoWeek, formatIsoWeek, getAggregatedData } from './shared-aggregation.js';
 17→import type { ReflectSection } from '@code-insights/cli/types';
 18→
 19→const app = new Hono();
 20→
 21→const MIN_FACETS_FOR_REFLECT = 8;
 22→
 23→const ALL_SECTIONS: ReflectSection[] = ['friction-wins', 'rules-skills', 'working-style'];
 24→
 25→// Parse LLM JSON response wrapped in <json>...</json> tags with jsonrepair fallback.
 26→function parseLLMJson<T>(response: string): T | null {
 27→  const payload = extractJsonPayload(response);
 28→  if (!payload) return null;
 29→  try {
 30→    return JSON.parse(payload) as T;
 31→  } catch {
 32→    try {
 33→      return JSON.parse(jsonrepair(payload)) as T;
 34→    } catch {
 35→      return null;
 36→    }
 37→  }
 38→}
 39→
 40→// Detect the dominant source tool from the database to target artifact generation.
 41→function detectTargetTool(db: ReturnType<typeof getDb>): string {
 42→  const row = db.prepare(
 43→    `SELECT source_tool, COUNT(*) as count FROM sessions WHERE deleted_at IS NULL GROUP BY source_tool ORDER BY count DESC LIMIT 1`
 44→  ).get() as { source_tool: string; count: number } | undefined;
 45→  return row?.source_tool || 'claude-code';
 46→}
 47→
 48→// POST /api/reflect/generate
 49→// Body: { sections?: ReflectSection[], period?: string, project?: string, source?: string }
 50→// SSE endpoint: aggregates facets in code, then calls synthesis prompts for each section.
 51→// Streams progress events so the UI can show phase-by-phase progress.
 52→app.post('/generate', requireLLM(), async (c) => {
 53→
 54→  const body = await c.req.json<{
 55→    sections?: ReflectSection[];
 56→    period?: string;
 57→    project?: string;
 58→    source?: string;
 59→  }>();
 60→
 61→  const sections = body.sections && body.sections.length > 0 ? body.sections : ALL_SECTIONS;
 62→  const period = body.period || '30d';
 63→
 64→  const db = getDb();
 65→  const { where, params } = buildWhereClause(period, body.project, body.source);
 66→
 67→  return streamSSE(c, async (stream) => {
 68→    const abortSignal = c.req.raw.signal;
 69→
 70→    try {
 71→      await stream.writeSSE({
 72→        event: 'progress',
 73→        data: JSON.stringify({ phase: 'aggregating', message: 'Aggregating facets...' }),
 74→      });
 75→
 76→      const aggregated = getAggregatedData(db, where, params, body.project, body.source);
 77→
 78→      if (aggregated.totalSessions === 0) {
 79→        await stream.writeSSE({
 80→          event: 'error',
 81→          data: JSON.stringify({ error: 'No sessions with facets found. Run analysis first.' }),
 82→        });
 83→        return;
 84→      }
 85→
 86→      if (aggregated.totalSessions < MIN_FACETS_FOR_REFLECT) {
 87→        await stream.writeSSE({
 88→          event: 'error',
 89→          data: JSON.stringify({
 90→            error: `Need at least ${MIN_FACETS_FOR_REFLECT} analyzed sessions for meaningful pattern synthesis. Currently have ${aggregated.totalSessions}. Run session analysis on more sessions first.`,
 91→            code: 'INSUFFICIENT_FACETS',
 92→            current: aggregated.totalSessions,
 93→            required: MIN_FACETS_FOR_REFLECT,
 94→          }),
 95→        });
 96→        return;
 97→      }
 98→
 99→      const client = createLLMClient();
100→      const results: Record<string, unknown> = {};
101→      const targetTool = detectTargetTool(db);
102→
103→      for (const section of sections) {
104→        if (abortSignal.aborted) break;
105→
106→        await stream.writeSSE({
107→          event: 'progress',
108→          data: JSON.stringify({ phase: 'synthesizing', section, message: `Generating ${section}...` }),
109→        });
110→
111→        if (section === 'friction-wins') {
112→          const prompt = generateFrictionWinsPrompt({
113→            frictionCategories: aggregated.frictionCategories,
114→            effectivePatterns: aggregated.effectivePatterns,
115→            totalSessions: aggregated.totalSessions,
116→            period,
117→            pqSignals: (aggregated.pqDeficits.length || aggregated.pqStrengths.length)
118→              ? { deficits: aggregated.pqDeficits, strengths: aggregated.pqStrengths }
119→              : undefined,
120→          });
121→          const response = await client.chat([
122→            { role: 'system', content: FRICTION_WINS_SYSTEM_PROMPT },
123→            { role: 'user', content: prompt },
124→          ], { signal: abortSignal });
125→          const parsed = parseLLMJson(response.content);
126→          results['friction-wins'] = {
127→            section: 'friction-wins',
128→            ...(parsed ?? {}),
129→            frictionCategories: aggregated.frictionCategories,
130→            effectivePatterns: aggregated.effectivePatterns,
131→            pqDeficits: aggregated.pqDeficits,
132→            pqStrengths: aggregated.pqStrengths,
133→            generatedAt: new Date().toISOString(),
134→          };
135→        } else if (section === 'rules-skills') {
136→          // Only include patterns with sufficient occurrence counts for actionable artifacts
137→          const recurringFriction = aggregated.frictionCategories.filter(fc => fc.count >= 3);
138→          const recurringPatterns = aggregated.effectivePatterns.filter(ep => ep.frequency >= 2);
139→          const prompt = generateRulesSkillsPrompt({
140→            recurringFriction,
141→            effectivePatterns: recurringPatterns,
142→            targetTool,
143→          });
144→          const response = await client.chat([
145→            { role: 'system', content: RULES_SKILLS_SYSTEM_PROMPT },
146→            { role: 'user', content: prompt },
147→          ], { signal: abortSignal });
148→          const parsed = parseLLMJson(response.content);
149→          results['rules-skills'] = {
150→            section: 'rules-skills',
151→            ...(parsed ?? {}),
152→            targetTool,
153→            generatedAt: new Date().toISOString(),
154→          };
155→        } else if (section === 'working-style') {
156→          const prompt = generateWorkingStylePrompt({
157→            workflowDistribution: aggregated.workflowDistribution,
158→            outcomeDistribution: aggregated.outcomeDistribution,
159→            characterDistribution: aggregated.characterDistribution,
160→            totalSessions: aggregated.totalSessions,
161→            period,
162→            frictionFrequency: aggregated.frictionTotal,
163→          });
164→          const response = await client.chat([
165→            { role: 'system', content: WORKING_STYLE_SYSTEM_PROMPT },
166→            { role: 'user', content: prompt },
167→          ], { signal: abortSignal });
168→          const parsed = parseLLMJson(response.content);
169→          // Sanitize tagline: must be a string ≤40 chars. Non-string LLM outputs
170→          // (object, array, number) are normalized to undefined so they don't
171→          // corrupt the snapshot blob stored in SQLite.
172→          const rawTagline = parsed && (parsed as Record<string, unknown>)['tagline'];
173→          const tagline = typeof rawTagline === 'string'
174→            ? rawTagline.slice(0, 40)
175→            : undefined;
176→          results['working-style'] = {
177→            section: 'working-style',
178→            ...(parsed ?? {}),
179→            tagline,
180→            workflowDistribution: aggregated.workflowDistribution,
181→            outcomeDistribution: aggregated.outcomeDistribution,
182→            characterDistribution: aggregated.characterDistribution,
183→            generatedAt: new Date().toISOString(),
184→          };
185→        }
186→      }
187→
188→      // Only save snapshot if the request was not aborted mid-generation.
189→      // Saving partial results would cause stale/incomplete data to auto-load on next visit.
190→      if (!c.req.raw.signal.aborted) {
191→        // For ISO week periods, use the exact week boundaries as window metadata.
192→        // This ensures the snapshot metadata accurately reflects the week it covers.
193→        const isoWeekBounds = parseIsoWeek(period);
194→        const windowStart = isoWeekBounds
195→          ? isoWeekBounds.start.toISOString()
196→          : buildPeriodFilter(period);
197→        const windowEnd = isoWeekBounds
198→          ? isoWeekBounds.end.toISOString()
199→          : new Date().toISOString();
200→        const projectKey = body.project || '__all__';
201→
202→        db.prepare(`
203→          INSERT INTO reflect_snapshots (period, project_id, results_json, generated_at, window_start, window_end, session_count, facet_count)
204→          VALUES (?, ?, ?, ?, ?, ?, ?, ?)
205→          ON CONFLICT(period, project_id) DO UPDATE SET
206→            results_json = excluded.results_json,
207→            generated_at = excluded.generated_at,
208→            window_start = excluded.window_start,
209→            window_end = excluded.window_end,
210→            session_count = excluded.session_count,
211→            facet_count = excluded.facet_count
212→        `).run(
213→          period,
214→          projectKey,
215→          JSON.stringify(results),
216→          new Date().toISOString(),
217→          windowStart,
218→          windowEnd,
219→          aggregated.totalSessions,
220→          aggregated.frictionTotal
221→        );
222→      }
223→
224→      await stream.writeSSE({
225→        event: 'complete',
226→        data: JSON.stringify({ results }),
227→      });
228→    } catch (err) {
229→      const message = err instanceof Error ? err.message : 'Unknown error';
230→      await stream.writeSSE({
231→        event: 'error',
232→        data: JSON.stringify({ error: message }),
233→      }).catch(() => {});
234→    }
235→  });
236→});
237→
238→// GET /api/reflect/results
239→// Returns raw aggregated facet data without LLM synthesis (fast, no cost).
240→// The full synthesized view requires POST /api/reflect/generate.
241→app.get('/results', (c) => {
242→  const db = getDb();
243→  const period = c.req.query('period') || '30d';
244→  const project = c.req.query('project');
245→  const source = c.req.query('source');
246→
247→  const { where, params } = buildWhereClause(period, project, source);
248→  const aggregated = getAggregatedData(db, where, params, project, source);
249→
250→  return c.json(aggregated);
251→});
252→
253→// GET /api/reflect/weeks
254→// Returns all ISO weeks from the earliest session through the current week, with snapshot status.
255→// Used by the WeekSelector component to show which weeks have reflections.
256→// Week list is data-driven (not capped at 8) so users with long history can navigate all weeks.
257→app.get('/weeks', (c) => {
258→  const db = getDb();
259→  const project = c.req.query('project');
260→
261→  const projectCondition = project ? 'AND project_id = ?' : '';
262→  const projectParams: string[] = project ? [project] : [];
263→
264→  // Find the earliest session to determine the full week range.
265→  // If no sessions exist, return empty array.
266→  const earliestRow = db.prepare(`
267→    SELECT MIN(started_at) as earliest
268→    FROM sessions
269→    WHERE deleted_at IS NULL
270→      ${projectCondition}
271→  `).get(...projectParams) as { earliest: string | null } | undefined;
272→
273→  if (!earliestRow?.earliest) {
274→    return c.json({ weeks: [] });
275→  }
276→
277→  // Compute the UTC midnight of the Monday of the current ISO week.
278→  // Truncating to midnight ensures the while-loop comparison is stable
279→  // regardless of the time-of-day component in started_at values.
280→  const now = new Date();
281→  const nowDay = now.getUTCDay(); // 0=Sun
282→  const daysToMonday = nowDay === 0 ? 6 : nowDay - 1;
283→  const thisMondayMs = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()) - daysToMonday * 86400000;
284→
285→  // Compute the UTC midnight of the Monday of the earliest session's ISO week.
286→  const earliestDate = new Date(earliestRow.earliest);
287→  const earliestDay = earliestDate.getUTCDay();
288→  const daysToEarliestMonday = earliestDay === 0 ? 6 : earliestDay - 1;
289→  const earliestMondayMs = Date.UTC(earliestDate.getUTCFullYear(), earliestDate.getUTCMonth(), earliestDate.getUTCDate()) - daysToEarliestMonday * 86400000;
290→
291→  // Generate all weeks from earliest through current (most recent first).
292→  // Cap at 520 weeks (~10 years) to stay under SQLite's 999 bind-variable limit
293→  // for the snapshot IN (...) query (each week uses 1 placeholder + 1 for project_id).
294→  const MAX_WEEKS = 520;
295→  type WeekEntry = { week: string; start: string; end: string };
296→  const weekEntries: WeekEntry[] = [];
297→  let weekMondayMs = thisMondayMs;
298→  while (weekMondayMs >= earliestMondayMs && weekEntries.length < MAX_WEEKS) {
299→    const weekMonday = new Date(weekMondayMs);
300→    const week = formatIsoWeek(weekMonday);
301→    const bounds = parseIsoWeek(week)!;
302→    weekEntries.push({ week, start: bounds.start.toISOString(), end: bounds.end.toISOString() });
303→    weekMondayMs -= 7 * 86400000;
304→  }
305→
306→  const projectKey = project || '__all__';
307→
308→  // Query 1: session counts per ISO week using GROUP BY.
309→  // The Thursday trick: 'weekday 4' advances to the ISO week's Thursday (or stays if already
310→  // Thursday), then '-3 days' gives that week's Monday. This handles all 7 days correctly —
311→  // unlike 'weekday 1, -7 days' which overshoots by one week for sessions starting on Monday.
312→  // Returns one row per week that has sessions — O(sessions), not O(weeks).
313→  const rangeStart = weekEntries[weekEntries.length - 1].start;
314→  const rangeEnd = weekEntries[0].end;
315→
316→  const sessionCountRaw = db.prepare(`
317→    SELECT
318→      date(s.started_at, 'weekday 4', '-3 days') as week_monday,
319→      COUNT(*) as cnt
320→    FROM sessions s
321→    WHERE s.deleted_at IS NULL
322→      AND s.started_at >= ?
323→      AND s.started_at < ?
324→      ${projectCondition}
325→    GROUP BY week_monday
326→  `).all(
327→    rangeStart,
328→    rangeEnd,
329→    ...projectParams
330→  ) as Array<{ week_monday: string; cnt: number }>;
331→
332→  // Build a map from ISO week string -> session count.
333→  // week_monday is a YYYY-MM-DD string (SQLite date()); parse it and derive the ISO week string.
334→  const sessionCountMap = new Map<string, number>();
335→  for (const row of sessionCountRaw) {
336→    const monday = new Date(row.week_monday + 'T00:00:00Z');
337→    const weekStr = formatIsoWeek(monday);
338→    // Accumulate in case formatIsoWeek maps two slightly-different Mondays to the same week
339→    sessionCountMap.set(weekStr, (sessionCountMap.get(weekStr) ?? 0) + row.cnt);
340→  }
341→
