 33→  const db = getDb();
 34→  const project = c.req.query('project');
 35→  const period = c.req.query('period') || '30d';
 36→  const source = c.req.query('source');
 37→
 38→  const { where, params } = buildWhereClause(period, project, source);
 39→
 40→  // Total sessions in scope
 41→  const totalRow = db.prepare(
 42→    `SELECT COUNT(*) as count FROM sessions s ${where}`
 43→  ).get(...params) as { count: number };
 44→
 45→  // Sessions with facets — join to sessions so period/project/source filters apply
 46→  const facets = db.prepare(
 47→    `SELECT sf.* FROM session_facets sf
 48→     JOIN sessions s ON sf.session_id = s.id
 49→     ${where}
 50→     ORDER BY s.started_at DESC`
 51→  ).all(...params) as FacetRow[];
 52→
 53→  return c.json({
 54→    facets,
 55→    missingCount: totalRow.count - facets.length,
 56→    totalSessions: totalRow.count,
