 78→app.get('/missing', (c) => {
 79→  const db = getDb();
 80→  const period = c.req.query('period') || 'all';
 81→  const project = c.req.query('project');
 82→  const source = c.req.query('source');
 83→
 84→  // buildWhereClause can't be used here — it generates "WHERE ..." prefix,
 85→  // but this query already needs "WHERE sf.session_id IS NULL".
 86→  // Build conditions inline instead.
 87→  const conditions: string[] = ['sf.session_id IS NULL', 's.deleted_at IS NULL'];
 88→  const params: (string | number)[] = [];
 89→
 90→  if (period !== 'all') {
 91→    const now = new Date();
 92→    const days = period === '7d' ? 7 : period === '30d' ? 30 : period === '90d' ? 90 : 0;
 93→    if (days > 0) {
 94→      conditions.push('s.started_at >= ?');
 95→      params.push(new Date(now.getTime() - days * 86400000).toISOString());
 96→    }
 97→  }
 98→  if (project) {
 99→    conditions.push('s.project_id = ?');
100→    params.push(project);
101→  }
102→  if (source) {
103→    conditions.push('s.source_tool = ?');
104→    params.push(source);
105→  }
106→
107→  const where = `WHERE ${conditions.join(' AND ')}`;
108→
109→  const rows = db.prepare(`
110→    SELECT DISTINCT i.session_id
111→    FROM insights i
112→    JOIN sessions s ON i.session_id = s.id
113→    LEFT JOIN session_facets sf ON i.session_id = sf.session_id
114→    ${where}
115→  `).all(...params) as Array<{ session_id: string }>;
116→
117→  const sessionIds = rows.map(r => r.session_id);
118→  return c.json({ sessionIds, count: sessionIds.length });
