121→// GET /api/facets/outdated
122→// Returns count and sessionIds of session_facets rows where:
123→//   - effective_patterns entries lack a category or driver field, OR
124→//   - friction_points entries lack an attribution field
125→// Accepts period + project to scope to the user's current view — avoids misleading counts
126→// when the user is viewing "last 7 days" but sees outdated sessions from all time.
127→app.get('/outdated', (c) => {
128→  const db = getDb();
129→  const project = c.req.query('project');
130→  const period = c.req.query('period') || '30d';
131→
132→  const { where, params } = buildWhereClause(period, project);
133→
134→  // UNION of two subqueries — each finds session_ids with a specific outdated signal.
135→  // UNION (not UNION ALL) deduplicates sessions that fail both checks.
136→  // The effective_patterns arm uses OR to catch both missing category and missing driver
137→  // in a single scan rather than two separate UNION arms.
138→  const rows = db.prepare(`
139→    SELECT DISTINCT sf.session_id
140→    FROM session_facets sf
141→    JOIN sessions s ON sf.session_id = s.id
142→    CROSS JOIN json_each(sf.effective_patterns) je
143→    ${where}
144→    AND json_array_length(sf.effective_patterns) > 0
145→    AND (json_extract(je.value, '$.category') IS NULL
146→         OR json_extract(je.value, '$.driver') IS NULL)
147→    UNION
148→    SELECT DISTINCT sf.session_id
149→    FROM session_facets sf
150→    JOIN sessions s ON sf.session_id = s.id
151→    CROSS JOIN json_each(sf.friction_points) je
152→    ${where}
153→    AND json_array_length(sf.friction_points) > 0
154→    AND json_extract(je.value, '$.attribution') IS NULL
155→  `).all(...params, ...params) as Array<{ session_id: string }>;
156→
157→  const sessionIds = rows.map(r => r.session_id);
158→  return c.json({ count: sessionIds.length, sessionIds });
159→});
