163→// Streams progress as facets are extracted one-by-one for sessions that lack them.
164→// force=true skips the existing-facets guard, allowing re-extraction of outdated rows.
165→// Uses extractFacetsOnly (lightweight prompt: summary + first/last 20 messages).
166→app.post('/backfill', requireLLM(), async (c) => {
167→
168→  const body = await c.req.json<{ sessionIds?: string[]; force?: boolean }>();
169→  if (!body.sessionIds || !Array.isArray(body.sessionIds) || body.sessionIds.length === 0) {
170→    return c.json({ error: 'sessionIds array required' }, 400);
171→  }
172→  if (body.sessionIds.length > MAX_BACKFILL_SESSIONS) {
173→    return c.json({ error: `Maximum ${MAX_BACKFILL_SESSIONS} sessions per backfill request` }, 400);
174→  }
175→
176→  const db = getDb();
177→
178→  return streamBatchBackfill(c, body.sessionIds, body.force ?? false, {
179→    shouldSkip: (sessionId) => {
180→      return !!db.prepare('SELECT 1 FROM session_facets WHERE session_id = ?').get(sessionId);
181→    },
182→    analysisFn: extractFacetsOnly,
183→  });
184→});
