 1→// LLM client factory — server-side.
 2→// Config is loaded from ~/.code-insights/config.json via the CLI config system.
 3→// No localStorage or browser APIs used here.
 4→
 5→import { loadConfig } from '@code-insights/cli/utils/config';
 6→import type { LLMClient } from './types.js';
 7→import type { LLMProviderConfig } from './types.js';
 8→import { createOpenAIClient } from './providers/openai.js';
 9→import { createAnthropicClient } from './providers/anthropic.js';
10→import { createGeminiClient } from './providers/gemini.js';
11→import { createOllamaClient } from './providers/ollama.js';
12→
13→/**
14→ * Load LLM config from the CLI config file.
15→ */
16→export function loadLLMConfig(): LLMProviderConfig | null {
17→  const config = loadConfig();
18→  return config?.dashboard?.llm ?? null;
19→}
20→
21→/**
22→ * Check if LLM is configured.
23→ */
24→export function isLLMConfigured(): boolean {
25→  const llm = loadLLMConfig();
26→  if (!llm) return false;
27→  if (llm.provider === 'ollama') return !!llm.model;
28→  return !!llm.apiKey && !!llm.model;
29→}
30→
31→/**
32→ * Create an LLM client from the current config.
33→ * Throws if LLM is not configured.
34→ */
35→export function createLLMClient(): LLMClient {
36→  const config = loadLLMConfig();
37→  if (!config) {
38→    throw new Error('LLM not configured. Run `code-insights config llm` to configure a provider.');
39→  }
40→  return createClientFromConfig(config);
41→}
42→
43→/**
44→ * Create an LLM client from a specific config object (used for testing).
45→ */
46→export function createClientFromConfig(config: LLMProviderConfig): LLMClient {
47→  switch (config.provider) {
48→    case 'openai':
49→      return createOpenAIClient(config.apiKey ?? '', config.model);
50→    case 'anthropic':
51→      return createAnthropicClient(config.apiKey ?? '', config.model);
52→    case 'gemini':
53→      return createGeminiClient(config.apiKey ?? '', config.model);
54→    case 'ollama':
55→      return createOllamaClient(config.model, config.baseUrl);
56→    default:
57→      throw new Error(`Unknown LLM provider: ${config.provider}`);
58→  }
59→}
60→
61→/**
62→ * Test LLM connectivity with the given config.
63→ */
64→export async function testLLMConfig(config: LLMProviderConfig): Promise<{ success: boolean; error?: string }> {
65→  try {
66→    const client = createClientFromConfig(config);
67→    await client.chat([{ role: 'user', content: 'Say "ok" and nothing else.' }]);
68→    return { success: true };
69→  } catch (error) {
70→    return {
71→      success: false,
72→      error: error instanceof Error ? error.message : 'Unknown error',
73→    };
74→  }
75→}
