 55→
 56→  const { sessionIds, projectId, template = 'knowledge-base' } = body;
 57→
 58→  if (template !== 'knowledge-base' && template !== 'agent-rules') {
 59→    return c.json({ error: 'template must be "knowledge-base" or "agent-rules"' }, 400);
 60→  }
 61→  if (sessionIds !== undefined && !Array.isArray(sessionIds)) {
 62→    return c.json({ error: 'sessionIds must be an array' }, 400);
 63→  }
 64→  if (sessionIds && (sessionIds as unknown[]).some((id) => typeof id !== 'string')) {
 65→    return c.json({ error: 'sessionIds must contain only strings' }, 400);
 66→  }
 67→  if (sessionIds && sessionIds.length > 100) {
 68→    return c.json({ error: 'Maximum 100 session IDs per export request' }, 400);
 69→  }
 70→
 71→  let sessions: SessionRow[];
 72→  if (sessionIds && sessionIds.length > 0) {
 73→    const placeholders = sessionIds.map(() => '?').join(', ');
 74→    sessions = db.prepare(
 75→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 76→              message_count, estimated_cost_usd, session_character, source_tool
 77→       FROM sessions WHERE id IN (${placeholders}) AND deleted_at IS NULL ORDER BY started_at DESC`,
 78→    ).all(...sessionIds) as SessionRow[];
 79→  } else if (projectId) {
 80→    // Cap at 100 to avoid unbounded queries and SQLite variable limit on insight fetch
 81→    sessions = db.prepare(
 82→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 83→              message_count, estimated_cost_usd, session_character, source_tool
 84→       FROM sessions WHERE project_id = ? AND deleted_at IS NULL ORDER BY started_at DESC LIMIT 100`,
 85→    ).all(projectId) as SessionRow[];
 86→  } else {
 87→    // "Everything" export — most recent 100 sessions
 88→    sessions = db.prepare(
 89→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
 90→              message_count, estimated_cost_usd, session_character, source_tool
 91→       FROM sessions WHERE deleted_at IS NULL ORDER BY started_at DESC LIMIT 100`,
 92→    ).all() as SessionRow[];
 93→  }
 94→
 95→  const insights = fetchInsightsForSessions(db, sessions.map((s) => s.id));
 96→
 97→  const markdown =
 98→    template === 'agent-rules'
 99→      ? formatAgentRules(sessions, insights)
100→      : formatKnowledgeBase(sessions, insights);
101→
102→  trackEvent('export_run', {
103→    format: 'markdown',
104→    template,
105→    session_count: sessions.length,
106→    insight_count: insights.length,
107→    success: true,
108→  });
109→
110→  c.header('Content-Type', 'text/markdown');
111→  return c.body(markdown);
112→});
