13→function getWeekKey(dateStr: string): string {
14→  const date = new Date(dateStr);
15→  const start = startOfWeek(date, { weekStartsOn: 1 });
16→  return format(start, 'yyyy-MM-dd');
17→}
18→
19→function getWeekLabel(weekKey: string): string {
20→  const start = new Date(weekKey + 'T00:00:00');
21→  const end = endOfWeek(start, { weekStartsOn: 1 });
22→  const now = new Date();
23→  const thisWeekStart = startOfWeek(now, { weekStartsOn: 1 });
24→  const lastWeekStart = startOfWeek(subWeeks(now, 1), { weekStartsOn: 1 });
25→
26→  if (weekKey === format(thisWeekStart, 'yyyy-MM-dd')) {
27→    return `This Week (${format(start, 'MMM d')} - ${format(end, 'MMM d')})`;
28→  }
29→  if (weekKey === format(lastWeekStart, 'yyyy-MM-dd')) {
30→    return `Last Week (${format(start, 'MMM d')} - ${format(end, 'MMM d')})`;
31→  }
32→  return `Week of ${format(start, 'MMMM d, yyyy')}`;
33→}
