11→    .option('-p, --period <period>', 'Time range: 7d, 30d, 90d, all', '7d')
12→    .option('--project <name>', 'Scope to a single project')
13→    .option('--source <tool>', 'Filter by source tool (claude-code, cursor, etc.)')
