13→ * Initialize Code Insights configuration.
14→ * Sets up sync preferences and initializes the local SQLite database.
15→ */
16→export async function initCommand(_options: InitOptions = {}): Promise<void> {
17→  console.log(chalk.cyan('\n  Code Insights Setup\n'));
18→
19→  if (isConfigured()) {
20→    const { overwrite } = await inquirer.prompt([
21→      {
22→        type: 'confirm',
23→        name: 'overwrite',
24→        message: 'Configuration already exists. Overwrite?',
25→        default: false,
26→      },
27→    ]);
28→
29→    if (!overwrite) {
30→      console.log(chalk.yellow('Setup cancelled.'));
31→      return;
32→    }
33→  }
34→
35→  // Save minimal config
36→  const config: ClaudeInsightConfig = {
37→    sync: { claudeDir: '~/.claude/projects', excludeProjects: [] },
38→  };
39→  saveConfig(config);
40→
41→  // Initialize database (creates schema if first run)
42→  try {
43→    getDb();
44→    console.log(chalk.green('\n  Database initialized at ~/.code-insights/data.db'));
45→  } catch (error) {
46→    console.log(chalk.red(`\n  Database initialization failed: ${error instanceof Error ? error.message : 'Unknown error'}`));
47→    const { error_type, error_message } = classifyError(error);
48→    trackEvent('cli_init', { success: false, error_type, error_message });
49→    captureError(error, { command: 'init', error_type });
50→    process.exit(1);
51→  }
52→
53→  console.log(chalk.green('\n  Configuration saved!'));
54→  console.log(chalk.gray(`  Config location: ${getConfigDir()}/config.json`));
55→
56→  console.log(chalk.cyan('\n  Setup complete! Next steps:\n'));
57→  console.log(chalk.white('  1. Sync your sessions:'));
58→  console.log(chalk.gray('     code-insights sync\n'));
59→  console.log(chalk.white('  2. View your stats:'));
60→  console.log(chalk.gray('     code-insights stats\n'));
