  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as os from 'os';
  4→import chalk from 'chalk';
  5→import { trackEvent, captureError, classifyError } from '../utils/telemetry.js';
  6→
  7→const CLAUDE_SETTINGS_DIR = path.join(os.homedir(), '.claude');
  8→const HOOKS_FILE = path.join(CLAUDE_SETTINGS_DIR, 'settings.json');
  9→
 10→interface ClaudeSettings {
 11→  hooks?: {
 12→    PostToolUse?: HookConfig[];
 13→    Stop?: HookConfig[];
 14→    [key: string]: HookConfig[] | undefined;
 15→  };
 16→  [key: string]: unknown;
 17→}
 18→
 19→interface HookConfig {
 20→  matcher?: string;
 21→  hooks: Array<string | { type: string; command: string; timeout?: number }>;
 22→}
 23→
 24→/** Extract command string from both old (string) and new ({type, command}) hook formats */
 25→function getHookCommand(hook: string | { type: string; command: string }): string {
 26→  return typeof hook === 'string' ? hook : hook.command;
 27→}
 28→
 29→/**
 30→ * Install Claude Code hook for auto-sync
 31→ */
 32→export async function installHookCommand(): Promise<void> {
 33→  console.log(chalk.cyan('\n🔗 Install Code Insights Hook\n'));
 34→
 35→  try {
 36→    // Get CLI path
 37→    const cliPath = process.argv[1];
 38→    const syncCommand = `node ${cliPath} sync -q`;
 39→
 40→    console.log(chalk.gray('This will add a Claude Code hook that syncs sessions automatically.'));
 41→    console.log(chalk.gray(`Hook command: ${syncCommand}\n`));
 42→
 43→    // Load existing settings
 44→    let settings: ClaudeSettings = {};
 45→    if (fs.existsSync(HOOKS_FILE)) {
 46→      try {
 47→        const content = fs.readFileSync(HOOKS_FILE, 'utf-8');
 48→        settings = JSON.parse(content);
 49→      } catch {
 50→        console.log(chalk.yellow('Could not parse existing settings.json, creating new one.'));
 51→      }
 52→    }
 53→
 54→    // Initialize hooks structure
 55→    if (!settings.hooks) {
 56→      settings.hooks = {};
 57→    }
 58→
 59→    // Add Stop hook (runs when Claude finishes responding)
 60→    const stopHook: HookConfig = {
 61→      hooks: [{ type: 'command', command: syncCommand }],
 62→    };
 63→
 64→    // Check if hook already exists
 65→    const existingStopHooks = settings.hooks.Stop || [];
 66→    const hookExists = existingStopHooks.some(
 67→      (h) => h.hooks.some((hook) => getHookCommand(hook).includes('code-insights'))
 68→    );
 69→
 70→    if (hookExists) {
 71→      console.log(chalk.yellow('Code Insights hook already installed.'));
 72→      console.log(chalk.gray('To reinstall, first run `code-insights uninstall-hook`'));
 73→      return;
 74→    }
 75→
 76→    settings.hooks.Stop = [...existingStopHooks, stopHook];
 77→
 78→    // Write settings
 79→    fs.mkdirSync(CLAUDE_SETTINGS_DIR, { recursive: true });
 80→    fs.writeFileSync(HOOKS_FILE, JSON.stringify(settings, null, 2));
 81→
 82→    console.log(chalk.green('Hook installed successfully!'));
 83→    console.log(chalk.gray(`\nConfiguration saved to: ${HOOKS_FILE}`));
 84→    console.log(chalk.cyan('\nHow it works:'));
 85→    console.log(chalk.white('  When a Claude Code session ends, the hook runs automatically'));
 86→    console.log(chalk.white('  Sessions are synced to your local database (~/.code-insights/data.db)'));
 87→    console.log(chalk.white('  Run `code-insights stats` anytime to see your analytics'));
 88→    trackEvent('cli_install_hook', { success: true });
 89→  } catch (error) {
 90→    console.log(chalk.red(`Failed to install hook: ${error instanceof Error ? error.message : 'Unknown error'}`));
 91→    const { error_type, error_message } = classifyError(error);
 92→    trackEvent('cli_install_hook', { success: false, error_type, error_message });
 93→    captureError(error, { command: 'install_hook', error_type });
 94→  }
 95→}
 96→
 97→/**
 98→ * Uninstall Claude Code hook
 99→ */
100→export async function uninstallHookCommand(): Promise<void> {
101→  console.log(chalk.cyan('\n🔗 Uninstall Code Insights Hook\n'));
102→
103→  if (!fs.existsSync(HOOKS_FILE)) {
104→    console.log(chalk.yellow('No hooks file found. Nothing to uninstall.'));
105→    return;
106→  }
107→
108→  try {
109→    const content = fs.readFileSync(HOOKS_FILE, 'utf-8');
110→    const settings: ClaudeSettings = JSON.parse(content);
111→
112→    if (!settings.hooks?.Stop) {
113→      console.log(chalk.yellow('No Stop hooks found. Nothing to uninstall.'));
114→      return;
115→    }
116→
117→    // Filter out Code Insights hooks
118→    settings.hooks.Stop = settings.hooks.Stop.filter(
119→      (h) => !h.hooks.some((hook) => getHookCommand(hook).includes('code-insights'))
120→    );
121→
122→    // Clean up empty arrays
123→    if (settings.hooks.Stop.length === 0) {
124→      delete settings.hooks.Stop;
125→    }
126→    if (Object.keys(settings.hooks).length === 0) {
127→      delete settings.hooks;
128→    }
129→
130→    fs.writeFileSync(HOOKS_FILE, JSON.stringify(settings, null, 2));
131→
132→    console.log(chalk.green('✅ Hook uninstalled successfully!'));
133→  } catch (error) {
134→    console.log(chalk.red('Failed to uninstall hook:'));
135→    console.error(error instanceof Error ? error.message : 'Unknown error');
136→  }
137→}
