 1→import chalk from 'chalk';
 2→import { loadSyncState } from '../utils/config.js';
 3→import { getDb, getDbPath } from '../db/client.js';
 4→import { getProjects } from '../db/read.js';
 5→import { getAllProviders } from '../providers/registry.js';
 6→import { trackEvent, captureError, classifyError } from '../utils/telemetry.js';
 7→
 8→/**
 9→ * Show Code Insights status
10→ */
11→export async function statusCommand(): Promise<void> {
12→  console.log(chalk.cyan('\n  Code Insights Status\n'));
13→
14→  try {
15→    // Check database
16→    console.log(chalk.white('Database:'));
17→    try {
18→      getDb(); // ensures migrations run
19→      const dbPath = getDbPath();
20→      console.log(chalk.green(`  Connected: ${dbPath}`));
21→
22→      const projects = getProjects();
23→      if (projects.length > 0) {
24→        const totalSessions = projects.reduce((sum, p) => sum + p.session_count, 0);
25→        console.log(chalk.gray(`  ${projects.length} projects, ${totalSessions} sessions synced`));
26→      } else {
27→        console.log(chalk.gray('  No sessions synced yet. Run `code-insights sync`'));
28→      }
29→    } catch (error) {
30→      console.log(chalk.red(`  Database error: ${error instanceof Error ? error.message : 'Unknown'}`));
31→    }
32→
33→    // Discover local sessions across all providers
34→    console.log(chalk.white('\nLocal Sessions:'));
35→    const providers = getAllProviders();
36→    let totalLocal = 0;
37→    for (const provider of providers) {
38→      try {
39→        const files = await provider.discover();
40→        if (files.length > 0) {
41→          console.log(chalk.green(`  ${provider.getProviderName()}: ${files.length} sessions`));
42→          totalLocal += files.length;
43→        }
44→      } catch {
45→        // Provider not available on this machine (e.g., no Cursor installed)
46→      }
47→    }
48→    if (totalLocal === 0) {
49→      console.log(chalk.yellow('  No sessions found from any tool'));
50→    }
51→
52→    // Check sync state
53→    console.log(chalk.white('\nSync State:'));
54→    const syncState = loadSyncState();
55→    if (syncState.lastSync) {
56→      const lastSync = new Date(syncState.lastSync);
57→      const syncedFiles = Object.keys(syncState.files).length;
58→      console.log(chalk.green(`  Last sync: ${lastSync.toLocaleString()}`));
59→      console.log(chalk.gray(`  ${syncedFiles} files tracked`));
60→    } else {
61→      console.log(chalk.yellow('  Never synced'));
62→      console.log(chalk.gray('  Run `code-insights sync` to sync'));
63→    }
64→
65→    // Synced projects list
66→    try {
67→      const projects = getProjects();
68→      if (projects.length > 0) {
69→        console.log(chalk.white('\nSynced Projects:'));
70→        for (const project of projects.slice(0, 5)) {
71→          console.log(chalk.gray(`  ${project.name} (${project.session_count} sessions)`));
72→        }
73→        if (projects.length > 5) {
74→          console.log(chalk.gray(`  ... and ${projects.length - 5} more`));
75→        }
76→      }
77→    } catch {
78→      // DB not ready yet
79→    }
80→
81→    console.log('');
82→    trackEvent('cli_status', { success: true });
83→  } catch (error) {
84→    const { error_type, error_message } = classifyError(error);
85→    trackEvent('cli_status', { success: false, error_type, error_message });
86→    captureError(error, { command: 'status', error_type });
87→    console.error(chalk.red(`  Status command failed: ${error instanceof Error ? error.message : 'Unknown error'}`));
88→  }
89→}
